/*
 * System V Shared Memory and Semaphores - Producer Consumer Demo
 * Compile: gcc -o producer_consumer producer_consumer.c
 * Run: ./producer_consumer
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/ipc.h>
#include <sys/shm.h>
#include <sys/sem.h>
#include <sys/wait.h>
#include <time.h>

// Union for semctl operations (required on some systems)
union semun {
 int val;
 struct semid_ds *buf;
 unsigned short *array;
};

// Shared buffer structure
#define BUFFER_SIZE 10
#define ITEM_SIZE 100

typedef struct {
 char buffer[BUFFER_SIZE][ITEM_SIZE];
 int in; // Producer writes at this index
 int out; // Consumer reads at this index
} SharedBuffer;

// Semaphore indices
#define MUTEX 0 // Binary semaphore for mutual exclusion
#define EMPTY 1 // Counting semaphore for empty slots
#define FULL 2 // Counting semaphore for filled slots
#define NUM_SEMS 3

// Semaphore operations
void sem_wait(int semid, int sem_num) {
 struct sembuf sb;
 sb.sem_num = sem_num;
 sb.sem_op = -1; // Decrement (wait)
 sb.sem_flg = 0;

 if (semop(semid, &sb, 1) == -1) {
 perror("semop wait failed");
 exit(1);
 }
}

void sem_signal(int semid, int sem_num) {
 struct sembuf sb;
 sb.sem_num = sem_num;
 sb.sem_op = 1; // Increment (signal)
 sb.sem_flg = 0;

 if (semop(semid, &sb, 1) == -1) {
 perror("semop signal failed");
 exit(1);
 }
}

// Initialize shared memory and semaphores
int init_ipc(key_t *key, int *shmid, int *semid) {
 // Generate key using ftok
 *key = ftok(".", 'S');
 if (*key == -1) {
 perror("ftok failed");
 return -1;
 }

 // Create shared memory segment
 *shmid = shmget(*key, sizeof(SharedBuffer), 0666 | IPC_CREAT | IPC_EXCL);
 if (*shmid == -1) {
 // Segment might already exist, try to get it
 *shmid = shmget(*key, sizeof(SharedBuffer), 0666);
 if (*shmid == -1) {
 perror("shmget failed");
 return -1;
 }
 }

 // Create semaphore set
 *semid = semget(*key, NUM_SEMS, 0666 | IPC_CREAT | IPC_EXCL);
 if (*semid == -1) {
 // Semaphores might already exist
 *semid = semget(*key, NUM_SEMS, 0666);
 if (*semid == -1) {
 perror("semget failed");
 return -1;
 }
 } else {
 // Initialize semaphores
 union semun arg;
 arg.val = 1;
 semctl(*semid, MUTEX, SETVAL, arg); // Binary semaphore = 1

 arg.val = BUFFER_SIZE;
 semctl(*semid, EMPTY, SETVAL, arg); // All slots empty

 arg.val = 0;
 semctl(*semid, FULL, SETVAL, arg); // No items yet
 }

 return 0;
}

// Attach to shared memory
SharedBuffer* attach_memory(int shmid) {
 SharedBuffer *shm_addr;

 shm_addr = (SharedBuffer*)shmat(shmid, NULL, 0);
 if (shm_addr == (void*)-1) {
 perror("shmat failed");
 return NULL;
 }

 return shm_addr;
}

// Producer process
void producer(int shmid, int semid, int num_items) {
 SharedBuffer *shm = attach_memory(shmid);
 if (!shm) exit(1);

 printf("Producer (PID %d) started\n", getpid());

 for (int i = 0; i < num_items; i++) {
 // Wait for empty slot
 sem_wait(semid, EMPTY);

 // Wait for mutex (enter critical section)
 sem_wait(semid, MUTEX);

 // Produce item
 snprintf(shm->buffer[shm->in], ITEM_SIZE, "Item-%d-PID-%d", i, getpid());
 printf("Producer: Produced '%s' at index %d\n", 
 shm->buffer[shm->in], shm->in);
 shm->in = (shm->in + 1) % BUFFER_SIZE;

 // Signal mutex (exit critical section)
 sem_signal(semid, MUTEX);

 // Signal that item is available
 sem_signal(semid, FULL);

 sleep(1); // Simulate production time
 }

 shmdt(shm);
 printf("Producer finished\n");
}

// Consumer process
void consumer(int shmid, int semid, int num_items) {
 SharedBuffer *shm = attach_memory(shmid);
 if (!shm) exit(1);

 printf("Consumer (PID %d) started\n", getpid());

 for (int i = 0; i < num_items; i++) {
 // Wait for available item
 sem_wait(semid, FULL);

 // Wait for mutex (enter critical section)
 sem_wait(semid, MUTEX);

 // Consume item
 printf("Consumer: Consumed '%s' from index %d\n", 
 shm->buffer[shm->out], shm->out);
 shm->out = (shm->out + 1) % BUFFER_SIZE;

 // Signal mutex (exit critical section)
 sem_signal(semid, MUTEX);

 // Signal that slot is empty
 sem_signal(semid, EMPTY);

 sleep(1); // Simulate consumption time
 }

 shmdt(shm);
 printf("Consumer finished\n");
}

// Cleanup function
void cleanup(int shmid, int semid) {
 // Remove shared memory
 if (shmctl(shmid, IPC_RMID, NULL) == -1) {
 perror("shmctl remove failed");
 }

 // Remove semaphore set
 if (semctl(semid, 0, IPC_RMID) == -1) {
 perror("semctl remove failed");
 }

 printf("IPC resources cleaned up\n");
}

int main(int argc, char *argv[]) {
 int shmid, semid;
 key_t key;
 int num_items = 5;

 printf("=== System V Shared Memory Producer-Consumer Demo ===\n\n");

 // Initialize IPC
 if (init_ipc(&key, &shmid, &semid) == -1) {
 // Try to get existing resources
 key = ftok(".", 'S');
 shmid = shmget(key, sizeof(SharedBuffer), 0666);
 semid = semget(key, NUM_SEMS, 0666);
 }

 printf("Created shared memory (ID: %d) and semaphores (ID: %d)\n\n", 
 shmid, semid);

 // Initialize shared buffer (first time only)
 SharedBuffer *shm = attach_memory(shmid);
 if (shm) {
 shm->in = 0;
 shm->out = 0;
 printf("Shared buffer initialized: in=0, out=0\n\n");
 shmdt(shm);
 }

 // Fork producer process
 pid_t prod_pid = fork();
 if (prod_pid == 0) {
 producer(shmid, semid, num_items);
 exit(0);
 }

 // Fork consumer process
 pid_t cons_pid = fork();
 if (cons_pid == 0) {
 consumer(shmid, semid, num_items);
 exit(0);
 }

 // Wait for both processes
 wait(NULL);
 wait(NULL);

 printf("\nBoth processes completed\n");

 // Cleanup
 cleanup(shmid, semid);

 return 0;
}
